  1→/**
  2→ * Phase detection and mapping utilities.
  3→ *
  4→ * Extracts label-to-phase detection logic and workflow parsing
  5→ * from the run command so it can be reused by batch-executor
  6→ * and other consumers.
  7→ *
  8→ * @module phase-mapper
  9→ */
 10→
 11→import type { Phase } from "./types.js";
 12→
 13→/**
 14→ * Minimal options interface for phase mapping.
 15→ * Avoids importing the full RunOptions from run.ts.
 16→ */
 17→interface PhaseMapperOptions {
 18→  testgen?: boolean;
 19→}
 20→
 21→/**
 22→ * UI-related labels that trigger automatic test phase
 23→ */
 24→export const UI_LABELS = ["ui", "frontend", "admin", "web", "browser"];
 25→
 26→/**
 27→ * Bug-related labels that skip spec phase
 28→ */
 29→export const BUG_LABELS = ["bug", "fix", "hotfix", "patch"];
 30→
 31→/**
 32→ * Documentation labels that skip spec phase
 33→ */
 34→export const DOCS_LABELS = ["docs", "documentation", "readme"];
 35→
 36→/**
 37→ * Complex labels that enable quality loop
 38→ */
 39→export const COMPLEX_LABELS = ["complex", "refactor", "breaking", "major"];
 40→
 41→/**
 42→ * Security-related labels that trigger security-review phase
 43→ */
 44→export const SECURITY_LABELS = [
 45→  "security",
 46→  "auth",
 47→  "authentication",
 48→  "permissions",
 49→  "admin",
 50→];
 51→
 52→/**
 53→ * Detect phases based on issue labels (like /assess logic)
 54→ */
 55→export function detectPhasesFromLabels(labels: string[]): {
 56→  phases: Phase[];
 57→  qualityLoop: boolean;
 58→} {
 59→  const lowerLabels = labels.map((l) => l.toLowerCase());
 60→
 61→  // Check for bug/fix labels → exec → qa (skip spec)
 62→  const isBugFix = lowerLabels.some((label) =>
 63→    BUG_LABELS.some((bugLabel) => label.includes(bugLabel)),
 64→  );
 65→
 66→  // Check for docs labels → exec → qa (skip spec)
 67→  const isDocs = lowerLabels.some((label) =>
 68→    DOCS_LABELS.some((docsLabel) => label.includes(docsLabel)),
 69→  );
 70→
 71→  // Check for UI labels → add test phase
 72→  const isUI = lowerLabels.some((label) =>
 73→    UI_LABELS.some((uiLabel) => label.includes(uiLabel)),
 74→  );
 75→
 76→  // Check for complex labels → enable quality loop
 77→  const isComplex = lowerLabels.some((label) =>
 78→    COMPLEX_LABELS.some((complexLabel) => label.includes(complexLabel)),
 79→  );
 80→
 81→  // Check for security labels → add security-review phase
 82→  const isSecurity = lowerLabels.some((label) =>
 83→    SECURITY_LABELS.some((secLabel) => label.includes(secLabel)),
 84→  );
 85→
 86→  // Build phase list
 87→  let phases: Phase[];
 88→
 89→  if (isBugFix || isDocs) {
 90→    // Simple workflow: exec → qa
 91→    phases = ["exec", "qa"];
 92→  } else if (isUI) {
 93→    // UI workflow: spec → exec → test → qa
 94→    phases = ["spec", "exec", "test", "qa"];
 95→  } else {
 96→    // Standard workflow: spec → exec → qa
 97→    phases = ["spec", "exec", "qa"];
 98→  }
 99→
100→  // Add security-review phase after spec if security labels detected
101→  if (isSecurity && phases.includes("spec")) {
102→    const specIndex = phases.indexOf("spec");
103→    phases.splice(specIndex + 1, 0, "security-review");
104→  }
105→
106→  return { phases, qualityLoop: isComplex };
107→}
108→
109→/**
110→ * Parse recommended workflow from /spec output
111→ *
112→ * Looks for:
113→ * ## Recommended Workflow
114→ * **Phases:** exec → qa
115→ * **Quality Loop:** enabled|disabled
116→ */
117→export function parseRecommendedWorkflow(output: string): {
118→  phases: Phase[];
119→  qualityLoop: boolean;
120→} | null {
121→  // Find the Recommended Workflow section
122→  const workflowMatch = output.match(
123→    /## Recommended Workflow[\s\S]*?\*\*Phases:\*\*\s*([^\n]+)/i,
124→  );
125→
126→  if (!workflowMatch) {
127→    return null;
128→  }
129→
130→  // Parse phases from "exec → qa" or "spec → exec → test → qa" format
131→  const phasesStr = workflowMatch[1].trim();
132→  const phaseNames = phasesStr
133→    .split(/\s*→\s*|\s*->\s*|\s*,\s*/)
134→    .map((p) => p.trim().toLowerCase())
135→    .filter((p) => p.length > 0);
136→
137→  // Validate and convert to Phase type
138→  const validPhases: Phase[] = [];
139→  for (const name of phaseNames) {
140→    if (
141→      [
142→        "spec",
143→        "security-review",
144→        "testgen",
145→        "exec",
146→        "test",
147→        "qa",
148→        "loop",
149→      ].includes(name)
150→    ) {
151→      validPhases.push(name as Phase);
152→    }
153→  }
154→
155→  if (validPhases.length === 0) {
156→    return null;
157→  }
158→
159→  // Parse quality loop setting
160→  const qualityLoopMatch = output.match(
161→    /\*\*Quality Loop:\*\*\s*(enabled|disabled|true|false|yes|no)/i,
162→  );
163→  const qualityLoop = qualityLoopMatch
164→    ? ["enabled", "true", "yes"].includes(qualityLoopMatch[1].toLowerCase())
165→    : false;
166→
167→  return { phases: validPhases, qualityLoop };
168→}
169→
170→/**
171→ * Check if an issue has UI-related labels
172→ */
173→export function hasUILabels(labels: string[]): boolean {
174→  return labels.some((label) =>
175→    UI_LABELS.some((uiLabel) => label.toLowerCase().includes(uiLabel)),
176→  );
177→}
178→
179→/**
180→ * Determine phases to run based on options and issue labels
181→ */
182→export function determinePhasesForIssue(
183→  basePhases: Phase[],
184→  labels: string[],
185→  options: PhaseMapperOptions,
186→): Phase[] {
