        }),
      );
    });

    it("should include workflow string in reason", () => {
      const workflow = {
        phases: ["test" as const],
        qualityLoop: false,
        issueNumbers: [123],
        workflowString: "spec → exec → test → qa",
      };

      const signals = solveWorkflowToSignals(workflow);

      expect(signals[0].reason).toContain("spec → exec → test → qa");
    });
  });

